#ifndef AVG_POOL3D_TILING_H_
#define AVG_POOL3D_TILING_H_

#include "kernel_operator.h"

enum AvgPool3dDataType : int32_t {
    AVGPOOL3D_DT_FLOAT16 = 0,
    AVGPOOL3D_DT_FLOAT32 = 1
};

struct AvgPool3dTiling {
    // Input shape
    int32_t n;
    int32_t d;
    int32_t h;
    int32_t w;
    int32_t c;

    // Output shape
    int32_t out_d;
    int32_t out_h;
    int32_t out_w;

    // Kernel
    int32_t k_d;
    int32_t k_h;
    int32_t k_w;

    // Stride
    int32_t s_d;
    int32_t s_h;
    int32_t s_w;

    // Padding: depth(front/back), height(top/bottom), width(left/right)
    int32_t pad_f;
    int32_t pad_b;
    int32_t pad_t;
    int32_t pad_bt;
    int32_t pad_l;
    int32_t pad_r;

    // Flags
    int32_t ceil_mode;           // 0 or 1
    int32_t count_include_pad;   // 0 or 1

    // Channel tiling (must be multiple of 16 for NDHWC alignment)
    int32_t c_tile;

    // Batch tiling for core split (each core processes a number of output points)
    int32_t points_per_core;

    // Data type
    int32_t inputType; // AvgPool3dDataType

    // Reserved
    int32_t reserved0;
    int32_t reserved1;
};

// Convenience: align up to a multiple
static inline __aicore__ int32_t align_up_int32(int32_t x, int32_t a) {
    return ((x + a - 1) / a) * a;
}

#endif // AVG_POOL3D_TILING_H_


