#include "kernel_operator.h"
#include "avg_pool3d_tiling.h"

using namespace AscendC;

template<typename T>
class KernelAvgPool3d {
public:
    __aicore__ inline KernelAvgPool3d() {}
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, const AvgPool3dTiling& tiling) {
        xGm.SetGlobalBuffer((__gm__ T*)x);
        yGm.SetGlobalBuffer((__gm__ T*)y);
        tiling_ = tiling;
        coreId_ = GetBlockIdx();
        blockNum_ = GetBlockNum();
        // Determine UB tiling: use tiling-provided c_tile and ensure multiple of 16 for NDHWC alignment
        cTile_ = tiling_.c_tile > 0 ? tiling_.c_tile : 128;
        cTile_ = align_up_int32(cTile_, 16);
        if (cTile_ > tiling_.c) cTile_ = align_up_int32(tiling_.c, 16); // clamp but keep alignment
        // Local buffers
        pipe.InitBuffer(inBuf1, cTile_);
        pipe.InitBuffer(accBuf, cTile_);       // float32 accumulator mapped via reinterpret for T
        pipe.InitBuffer(accF32Buf, cTile_);    // explicit float accumulation when T is half
    }

    __aicore__ inline void Process() {
        // total number of output points per batch across all batches
        int64_t totalPoints = static_cast<int64_t>(tiling_.n) *
                              static_cast<int64_t>(tiling_.out_d) *
                              static_cast<int64_t>(tiling_.out_h) *
                              static_cast<int64_t>(tiling_.out_w);
        // distribute points among cores
        int64_t pointsPerCore = tiling_.points_per_core > 0 ? tiling_.points_per_core
                                : (int64_t)((totalPoints + blockNum_ - 1) / blockNum_);
        int64_t startPoint = pointsPerCore * coreId_;
        int64_t endPoint = startPoint + pointsPerCore;
        if (startPoint >= totalPoints) return;
        if (endPoint > totalPoints) endPoint = totalPoints;

        for (int64_t p = startPoint; p < endPoint; ++p) {
            // decode linear index to (n, od, oh, ow)
            int64_t tmp = p;
            int32_t ow = tmp % tiling_.out_w;
            tmp /= tiling_.out_w;
            int32_t oh = tmp % tiling_.out_h;
            tmp /= tiling_.out_h;
            int32_t od = tmp % tiling_.out_d;
            int32_t n = tmp / tiling_.out_d;

            ComputePoint(n, od, oh, ow);
        }
    }

private:
    // NDHWC indexing helpers
    __aicore__ inline int64_t in_offset(int32_t n, int32_t d, int32_t h, int32_t w, int32_t c) const {
        return (((((int64_t)n * tiling_.d + d) * tiling_.h + h) * tiling_.w + w) * tiling_.c + c);
    }
    __aicore__ inline int64_t out_offset(int32_t n, int32_t d, int32_t h, int32_t w, int32_t c) const {
        return (((((int64_t)n * tiling_.out_d + d) * tiling_.out_h + h) * tiling_.out_w + w) * tiling_.c + c);
    }

    __aicore__ inline void ComputePoint(int32_t n, int32_t od, int32_t oh, int32_t ow) {
        // Determine window in input
        int32_t dStart = od * tiling_.s_d - tiling_.pad_f;
        int32_t hStart = oh * tiling_.s_h - tiling_.pad_t;
        int32_t wStart = ow * tiling_.s_w - tiling_.pad_l;
        int32_t dEnd = dStart + tiling_.k_d;
        int32_t hEnd = hStart + tiling_.k_h;
        int32_t wEnd = wStart + tiling_.k_w;

        // Clamp to input bounds
        int32_t d0 = dStart < 0 ? 0 : dStart;
        int32_t h0 = hStart < 0 ? 0 : hStart;
        int32_t w0 = wStart < 0 ? 0 : wStart;
        int32_t d1 = dEnd > tiling_.d ? tiling_.d : dEnd;
        int32_t h1 = hEnd > tiling_.h ? tiling_.h : hEnd;
        int32_t w1 = wEnd > tiling_.w ? tiling_.w : wEnd;

        int32_t validD = d1 - d0;
        int32_t validH = h1 - h0;
        int32_t validW = w1 - w0;

        int32_t windowVolume = tiling_.k_d * tiling_.k_h * tiling_.k_w;
        int32_t validCount = validD > 0 && validH > 0 && validW > 0 ? (validD * validH * validW) : 0;
        int32_t denom = tiling_.count_include_pad ? windowVolume : validCount;

        // If denom is zero (completely outside), output zeros
        bool zeroOut = (denom == 0);

        for (int32_t cStart = 0; cStart < tiling_.c; cStart += cTile_) {
            int32_t cLen = tiling_.c - cStart;
            if (cLen > cTile_) cLen = cTile_;
            // cLen must be multiple of 16 for NDHWC alignment; tail not aligned is not supported here
            // Ensure models layout/channel are aligned/padded to 16.
            int32_t alignedCLen = ((cLen + 15) / 16) * 16;
            int32_t effCLen = cLen;

            LocalTensor<T> inVec1 = inBuf1.Get<T>();
            LocalTensor<float> accF32 = accF32Buf.Get<float>();

            // init accumulators to zero
            for (int32_t i = 0; i < alignedCLen; ++i) {
                accF32.SetValue(i, 0.0f);
            }

            if (!zeroOut) {
                // Accumulate over valid window
                for (int32_t id = d0; id < d1; ++id) {
                    for (int32_t ih = h0; ih < h1; ++ih) {
                        for (int32_t iw = w0; iw < w1; ++iw) {
                            // GM->UB copy contiguous C slice
                            int64_t base = in_offset(n, id, ih, iw, cStart);
                            // DataCopy: use size effCLen, which must be aligned to 16 for NDHWC
                            // If C is padded to multiple of 16, effCLen will be aligned for cStart except possibly tail.
                            DataCopy(inVec1, xGm[base], effCLen);
                            // Accumulate into float
                            if constexpr (std::is_same<T, half>::value) {
                                for (int32_t i = 0; i < effCLen; ++i) {
                                    accF32[i] += static_cast<float>(inVec1.GetValue(i));
                                }
                            } else {
                                for (int32_t i = 0; i < effCLen; ++i) {
                                    accF32[i] += inVec1.GetValue(i);
                                }
                            }
                        }
                    }
                }
            }

            // Compute average and store
            LocalTensor<T> outVec = inBuf1.Get<T>(); // reuse buffer
            if (zeroOut) {
                for (int32_t i = 0; i < effCLen; ++i) outVec.SetValue(i, static_cast<T>(0));
            } else {
                float invDen = 1.0f / static_cast<float>(denom);
                if constexpr (std::is_same<T, half>::value) {
                    for (int32_t i = 0; i < effCLen; ++i) {
                        float v = accF32[i] * invDen;
                        outVec.SetValue(i, static_cast<half>(v));
                    }
                } else {
                    for (int32_t i = 0; i < effCLen; ++i) {
                        float v = accF32[i] * invDen;
                        outVec.SetValue(i, static_cast<float>(v));
                    }
                }
            }
            // Write back UB->GM
            int64_t outBase = out_offset(n, od, oh, ow, cStart);
            DataCopy(yGm[outBase], outVec, effCLen);
        }
    }

private:
    // Global tensors
    GlobalTensor<T> xGm;
    GlobalTensor<T> yGm;

    // Pipeline and UB buffers
    TPipe pipe;
    TBuf<UB> inBuf1;
    TBuf<UB> accBuf;
    TBuf<UB> accF32Buf;

    AvgPool3dTiling tiling_;
    int32_t cTile_;
    int32_t coreId_;
    int32_t blockNum_;
};

extern "C" __global__ __aicore__ void average_pool3d(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
    // Retrieve tiling data prepared by host
    GET_TILING_DATA(tiling_data, tiling);
    // Dispatch based on inputType
    if (tiling_data.inputType == AVGPOOL3D_DT_FLOAT16) {
        KernelAvgPool3d<half> op;
        op.Init(x, y, tiling_data);
        op.Process();
    } else {
        KernelAvgPool3d<float> op;
        op.Init(x, y, tiling_data);
        op.Process();
    }
}


