#include <cstdint>
#include <cmath>
#include <cstring>
#include "avg_pool3d_tiling.h"

// Note: The following host utilities assume an integration with AscendC runtime where
// a function like LaunchKernel is provided to launch the compiled kernel binary.
// Adapt as needed for your environment.

extern "C" void average_pool3d(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling);

// Compute output dims per axis
static inline int32_t compute_out_dim(int32_t in_size, int32_t k, int32_t s, int32_t pad0, int32_t pad1, int32_t ceil_mode) {
    int32_t effective = in_size + pad0 + pad1 - k;
    if (ceil_mode) {
        return (effective + s - 1) / s + 1;
    } else {
        return effective >= 0 ? (effective / s + 1) : 0;
    }
}

// Fill tiling based on attributes and shapes (NDHWC)
static inline void fill_tiling(AvgPool3dTiling &t,
                               int32_t n, int32_t d, int32_t h, int32_t w, int32_t c,
                               int32_t k_d, int32_t k_h, int32_t k_w,
                               int32_t s_d, int32_t s_h, int32_t s_w,
                               int32_t pad_f, int32_t pad_b, int32_t pad_t, int32_t pad_bt, int32_t pad_l, int32_t pad_r,
                               int32_t ceil_mode, int32_t count_include_pad,
                               int32_t inputType, int32_t blockNum, int32_t c_tile) {
    t.n = n; t.d = d; t.h = h; t.w = w; t.c = c;
    t.k_d = k_d; t.k_h = k_h; t.k_w = k_w;
    t.s_d = s_d; t.s_h = s_h; t.s_w = s_w;
    t.pad_f = pad_f; t.pad_b = pad_b; t.pad_t = pad_t; t.pad_bt = pad_bt; t.pad_l = pad_l; t.pad_r = pad_r;
    t.ceil_mode = ceil_mode;
    t.count_include_pad = count_include_pad;
    t.inputType = inputType;
    t.c_tile = c_tile > 0 ? c_tile : 128;

    t.out_d = compute_out_dim(d, k_d, s_d, pad_f, pad_b, ceil_mode);
    t.out_h = compute_out_dim(h, k_h, s_h, pad_t, pad_bt, ceil_mode);
    t.out_w = compute_out_dim(w, k_w, s_w, pad_l, pad_r, ceil_mode);

    int64_t totalPoints = (int64_t)n * t.out_d * t.out_h * t.out_w;
    int64_t pointsPerCore = (totalPoints + blockNum - 1) / blockNum;
    t.points_per_core = (int32_t)pointsPerCore;
}

// Minimal launcher example
// Replace LaunchKernel with the appropriate runtime call in your environment.
int avg_pool3d_launch(void* stream,
                      void* x_gm, void* y_gm, void* workspace_gm,
                      int32_t n, int32_t d, int32_t h, int32_t w, int32_t c,
                      int32_t k_d, int32_t k_h, int32_t k_w,
                      int32_t s_d, int32_t s_h, int32_t s_w,
                      int32_t pad_f, int32_t pad_b, int32_t pad_t, int32_t pad_bt, int32_t pad_l, int32_t pad_r,
                      int32_t ceil_mode, int32_t count_include_pad,
                      int32_t dataType, int32_t blockNum, int32_t c_tile)
{
    AvgPool3dTiling tiling{};
    fill_tiling(tiling,
                n, d, h, w, c,
                k_d, k_h, k_w,
                s_d, s_h, s_w,
                pad_f, pad_b, pad_t, pad_bt, pad_l, pad_r,
                ceil_mode, count_include_pad,
                dataType, blockNum, c_tile);

    // Ensure channel alignment for NDHWC (C multiple of 16) to match the kernel's assumption
    if ((c % 16) != 0) {
        // In production, pad C to multiple of 16 or add a tail-copy path using DataCopyPad
        return -1;
    }

    // Allocate GM for tiling struct in your runtime then pass GM_ADDR. Here, we assume we can pass by value.
    // Typically, Tile data is copied to GM and a pointer is passed to kernel.
    // The following is pseudo-code; replace with actual runtime API:
    // GM_ADDR tiling_gm = rtMalloc(..., sizeof(AvgPool3dTiling), ...);
    // rtMemcpy(tiling_gm, &tiling, sizeof(AvgPool3dTiling), ...);

    // For illustration we pass address of tiling as GM_ADDR (depends on environment)
    GM_ADDR tiling_gm = reinterpret_cast<GM_ADDR>(&tiling);

    // Launch kernel
    // Example: LaunchKernel(average_pool3d, blockNum, stream, x_gm, y_gm, workspace_gm, tiling_gm);
    average_pool3d(reinterpret_cast<GM_ADDR>(x_gm),
                   reinterpret_cast<GM_ADDR>(y_gm),
                   reinterpret_cast<GM_ADDR>(workspace_gm),
                   tiling_gm);

    return 0;
}


